INSERT INTO genres (genre_id, name, slug) VALUES
    ('b0000001-0000-0000-0000-000000000009', 'Espionage', 'espionage');
INSERT INTO movies (movie_id, title, description, duration, language, age_rating, trailer_url, poster_url, showing_start_date, showing_end_date, status) VALUES
    ('c0000002-0000-0000-000000000001', 'Person of Interest', 'You are being watched. The government has a secret system, a machine that spies on you every hour of every day. I know because I built it. I designed the Machine to detect acts of terror but it sees everything. Violent crimes involving ordinary people. People like you. Crimes the government considered "irrelevant". They wouldn''t act so I decided I would. But I needed a partner. Someone with the skills to intervene. Hunted by the authorities, we work in secret. You''ll never find us. But vict...', 60, 'English', 'T18', 'http://www.cbs.com/shows/person_of_interest/', 'https://static.tvmaze.com/uploads/images/medium_portrait/163/407679.jpg', '2011-09-22', '2012-03-22', 'INACTIVE'),
    ('c0000002-0000-0000-000000000002', 'Arrow', 'After a violent shipwreck, billionaire playboy Oliver Queen was missing and presumed dead for five years before being discovered alive on a remote island in the Pacific. He returned home to Starling City, welcomed by his devoted mother Moira, beloved sister Thea and former flame Laurel Lance. With the aid of his trusted chauffeur/bodyguard John Diggle, the computer-hacking skills of Felicity Smoak and the occasional, reluctant assistance of former police detective, now beat cop, Quentin Lance...', 60, 'English', 'T18', NULL, 'https://static.tvmaze.com/uploads/images/medium_portrait/143/358967.jpg', '2012-10-10', '2013-04-10', 'INACTIVE'),
    ('c0000002-0000-0000-000000000003', 'True Detective', 'Touch darkness and darkness touches you back. True Detective centers on troubled cops and the investigations that drive them to the edge. Each season features a new cast and a new case.True Detective is an American anthology crime drama television series created and written by Nic Pizzolatto.', 60, 'English', 'T18', 'https://www.max.com/shows/true-detective/9a4a3645-74e0-4e4d-9f35-31464b402357', 'https://static.tvmaze.com/uploads/images/medium_portrait/490/1226764.jpg', '2014-01-12', '2014-07-12', 'ACTIVE'),
    ('c0000002-0000-0000-000000000004', 'The Flash', 'After a particle accelerator causes a freak storm, CSI Investigator Barry Allen is struck by lightning and falls into a coma. Months later he awakens with the power of super speed, granting him the ability to move through Central City like an unseen guardian angel. Though initially excited by his newfound powers, Barry is shocked to discover he is not the only "meta-human" who was created in the wake of the accelerator explosion -- and not everyone is using their new powers for good. Barry pa...', 60, 'English', 'T18', 'http://www.cwtv.com/shows/the-flash/', 'https://static.tvmaze.com/uploads/images/medium_portrait/448/1121792.jpg', '2014-10-07', '2015-04-07', 'INACTIVE'),
    ('c0000002-0000-0000-000000000005', 'Supernatural', 'This haunting series follows the Winchester brothers as they crisscross the lonely and mysterious back roads of the country in their ''67 Chevy Impala, hunting down every evil supernatural force they encounter along the way.', 60, 'English', 'T18', 'http://www.cwtv.com/shows/supernatural', 'https://static.tvmaze.com/uploads/images/medium_portrait/445/1114097.jpg', '2005-09-13', '2006-03-13', 'INACTIVE'),
    ('c0000002-0000-0000-000000000006', 'American Horror Story', 'American Horror Story is an horror television anthology series. Each season is conceived as a self-contained miniseries, following a disparate set of characters and settings, and a storyline with its own beginning, middle, and end. While some actors appear for more than one year, they play completely different roles in each season.', 60, 'English', 'T18', 'http://www.fxnetworks.com/shows/american-horror-story', 'https://static.tvmaze.com/uploads/images/medium_portrait/473/1183640.jpg', '2011-10-05', '2012-04-05', 'ACTIVE'),
    ('c0000002-0000-0000-000000000007', 'Fargo', 'Fargo is a seasonal anthology crime drama with some dark comical elements, inspired by the film Fargo written by the Coen brothers. Each season follows a new case and new characters, all entrenched in the trademark humor, murder and "Minnesota nice" that has made the film an enduring classic.', 60, 'English', 'T18', 'http://www.fxnetworks.com/fargo', 'https://static.tvmaze.com/uploads/images/medium_portrait/487/1219631.jpg', '2014-04-15', '2014-10-15', 'COMING_SOON'),
    ('c0000002-0000-0000-000000000008', 'Outlander', 'Outlander follows the story of Claire Randall, a married combat nurse from 1945 who is mysteriously swept back in time to 1743, where she is immediately thrown into an unknown world where her life is threatened. When she is forced to marry Jamie, a chivalrous and romantic young Scottish warrior, a passionate affair is ignited that tears Claire''s heart between two vastly different men in two irreconcilable lives.The Outlander series, adapted from Diana Gabaldon''s international best-selling b...', 60, 'English', 'T18', 'https://www.starz.com/us/en/series/outlander/21796', 'https://static.tvmaze.com/uploads/images/medium_portrait/616/1541142.jpg', '2014-08-09', '2015-02-09', 'INACTIVE'),
    ('c0000002-0000-0000-000000000009', 'Chicago P.D.', 'District 21 of the Chicago Police Department is made up of two distinctly different groups. There are the uniformed cops who patrol the beat and go head to head with the city''s street crimes. And there''s the Intelligence Unit, the team that combats the city''s major offenses - organized crime, drug trafficking, high profile murders and beyond. These are their stories.', 60, 'English', 'T18', 'https://www.nbc.com/chicago-pd', 'https://static.tvmaze.com/uploads/images/medium_portrait/590/1475641.jpg', '2014-01-08', '2014-07-08', 'ACTIVE'),
    ('c0000002-0000-0000-000000000010', 'Chicago Fire', 'No job is more stressful, dangerous or exhilarating than those of the Firefighters, Rescue Squad and Paramedics of Chicago Firehouse 51. These are the courageous men and women who forge headfirst into danger when everyone else is running the other way and whose actions make the difference between life and death. These are their stories.', 60, 'English', 'T18', 'https://www.nbc.com/chicago-fire', 'https://static.tvmaze.com/uploads/images/medium_portrait/590/1475640.jpg', '2012-10-10', '2013-04-10', 'ACTIVE'),
    ('c0000002-0000-0000-000000000011', 'NCIS', 'NCIS (Naval Criminal Investigative Service) is more than just an action drama. With liberal doses of humor, it''s a show that focuses on the sometimes complex and always amusing dynamics of a team forced to work together in high-stress situations. Leroy Jethro Gibbs, a former Marine gunnery sergeant, whose skills as an investigator are unmatched, leads this troupe of colorful personalities. Rounding out the team are Anthony DiNozzo, an ex-homicide detective whose instincts in the field are un...', 60, 'English', 'T18', 'http://www.cbs.com/shows/ncis/', 'https://static.tvmaze.com/uploads/images/medium_portrait/591/1479851.jpg', '2003-09-23', '2004-03-23', 'ACTIVE'),
    ('c0000002-0000-0000-000000000012', 'Grey''s Anatomy', 'The doctors of Grey Sloan Memorial Hospital deal with life-or-death consequences on a daily basis -- it''s in one another that they find comfort, friendship and, at times, more than friendship. Together they''re discovering that neither medicine nor relationships can be defined in black and white. Real life only comes in shades of grey.', 60, 'English', 'T18', 'https://abc.com/shows/greys-anatomy/', 'https://static.tvmaze.com/uploads/images/medium_portrait/600/1501061.jpg', '2005-03-27', '2005-09-27', 'ACTIVE'),
    ('c0000002-0000-0000-000000000013', 'The Blacklist', 'The Blacklist is a crime drama involving a former government agent who turned into a high-profile criminal turning himself in to the FBI offering to help catch criminals.', 60, 'English', 'T18', 'https://www.nbc.com/the-blacklist', 'https://static.tvmaze.com/uploads/images/medium_portrait/445/1113538.jpg', '2013-09-23', '2014-03-23', 'INACTIVE'),
    ('c0000002-0000-0000-000000000014', 'Game of Thrones', 'Based on the bestselling book series A Song of Ice and Fire by George R.R. Martin, this sprawling new HBO drama is set in a world where summers span decades and winters can last a lifetime. From the scheming south and the savage eastern lands, to the frozen north and ancient Wall that protects the realm from the mysterious darkness beyond, the powerful families of the Seven Kingdoms are locked in a battle for the Iron Throne. This is a story of duplicity and treachery, nobility and honor, con...', 60, 'English', 'T18', 'http://www.hbo.com/game-of-thrones', 'https://static.tvmaze.com/uploads/images/medium_portrait/498/1245274.jpg', '2011-04-17', '2011-10-17', 'INACTIVE'),
    ('c0000002-0000-0000-000000000015', 'Blue Bloods', 'Blue Bloods is a drama about a multi-generational family of cops dedicated to New York City law enforcement. Frank Reagan is the New York Police Commissioner and heads both the police force and the Reagan brood. He runs his department as diplomatically as he runs his family, even when dealing with the politics that plagued his unapologetically bold father, Henry, during his stint as Chief. A source of pride and concern for Frank is his eldest son Danny, a seasoned detective, family man and Ir...', 60, 'English', 'T18', 'https://www.cbs.com/shows/blue_bloods/', 'https://static.tvmaze.com/uploads/images/medium_portrait/593/1482537.jpg', '2010-09-24', '2011-03-24', 'INACTIVE'),
    ('c0000002-0000-0000-000000000016', 'Law & Order: Special Victims Unit', 'In the criminal justice system, sexually-based offenses are considered especially heinous. In New York City, the dedicated detectives who investigate these vicious felonies are members of an elite squad known as the Special Victims Unit. These are their stories.', 60, 'English', 'T18', 'https://www.nbc.com/law-and-order-special-victims-unit', 'https://static.tvmaze.com/uploads/images/medium_portrait/589/1472924.jpg', '1999-09-20', '2000-03-20', 'ACTIVE'),
    ('c0000002-0000-0000-000000000017', 'Fringe', 'When an international flight lands at Boston''s Logan Airport and the passengers and crew have all died grisly deaths, FBI Special Agent Olivia Dunham is called in to investigate. After her partner is nearly killed during the investigation, a desperate Olivia searches frantically for someone to help, leading her to Dr. Walter Bishop, our generation''s Einstein. There''s only one catch: he''s been institutionalized for the last twenty years, and the only way to question him requires pulling hi...', 60, 'English', 'T18', NULL, 'https://static.tvmaze.com/uploads/images/medium_portrait/0/2245.jpg', '2008-09-09', '2009-03-09', 'INACTIVE'),
    ('c0000002-0000-0000-000000000018', 'Firefly', 'Five hundred years in the future, a renegade crew aboard a small spacecraft tries to survive as they travel the unknown parts of the galaxy and evade warring factions as well as authority agents out to get them.', 60, 'English', 'T18', NULL, 'https://static.tvmaze.com/uploads/images/medium_portrait/1/2600.jpg', '2002-09-20', '2003-03-20', 'INACTIVE'),
    ('c0000002-0000-0000-000000000019', 'Stargate SG┬╖1', 'Stargate SG-1 is a science fiction series based on the original film Stargate. It involves the team SG-1 going on various adventures to different alien worlds through Stargates. Throughout the series they encounter various alien threats and allies including but not limited to the Goa''uld and the Asgard.', 60, 'English', 'T18', 'http://stargate.mgm.com/view/series/1/index.html', 'https://static.tvmaze.com/uploads/images/medium_portrait/1/3027.jpg', '1997-07-27', '1998-01-27', 'INACTIVE'),
    ('c0000002-0000-0000-000000000020', 'The X-Files', 'Two FBI agents, Fox Mulder (a believer) and Dana Scully (a skeptic), investigate unexplained cases where the paranormal might be involved while hidden forces work to impede their efforts.', 60, 'English', 'T18', 'http://www.fox.com/the-x-files', 'https://static.tvmaze.com/uploads/images/medium_portrait/501/1253511.jpg', '1993-09-10', '1994-03-10', 'INACTIVE'),
    ('c0000002-0000-0000-000000000021', 'Under the Dome', 'Under the Dome is the story of a small town that is suddenly and inexplicably sealed off from the rest of the world by an enormous transparent dome. The town''s inhabitants must deal with surviving the post-apocalyptic conditions while searching for answers about the dome, where it came from and if and when it will go away.', 60, 'English', 'T13', 'http://www.cbs.com/shows/under-the-dome/', 'https://static.tvmaze.com/uploads/images/medium_portrait/610/1525272.jpg', '2013-06-24', '2013-12-24', 'INACTIVE'),
    ('c0000002-0000-0000-000000000022', 'The 100', 'Ninety-seven years ago, nuclear Armageddon decimated planet Earth, destroying civilization. The only survivors were the 400 inhabitants of 12 international space stations that were in orbit at the time. Three generations have been born in space, the survivors now number 4,000, and resources are running out on their dying "Ark" - the 12 stations now linked together and repurposed to keep the survivors alive. Draconian measures including capital punishment and population control are the order o...', 60, 'English', 'T18', NULL, 'https://static.tvmaze.com/uploads/images/medium_portrait/477/1194981.jpg', '2014-03-19', '2014-09-19', 'INACTIVE'),
    ('c0000002-0000-0000-000000000023', 'Homeland', 'The winner of 6 Emmy Awards including Outstanding Drama Series, Homeland is an edge-of-your-seat sensation. Marine Sergeant Nicholas Brody is both a decorated hero and a serious threat. CIA officer Carrie Mathison is tops in her field despite being bipolar. The delicate dance these two complex characters perform, built on lies, suspicion, and desire, is at the heart of this gripping, emotional thriller in which nothing short of the fate of our nation is at stake.', 60, 'English', 'T18', 'http://www.sho.com/sho/homeland/home', 'https://static.tvmaze.com/uploads/images/medium_portrait/498/1245275.jpg', '2011-10-02', '2012-04-02', 'INACTIVE'),
    ('c0000002-0000-0000-000000000024', 'Glee', 'Glee is a musical comedy about a group of ambitious and talented young adults in search of strength, acceptance and, ultimately, their voice.', 60, 'English', 'T13', 'http://www.fox.com/glee', 'https://static.tvmaze.com/uploads/images/medium_portrait/0/73.jpg', '2009-05-19', '2009-11-19', 'INACTIVE'),
    ('c0000002-0000-0000-000000000025', 'Grimm', 'Grimm is a drama series inspired by the classic Grimm Brothers'' Fairy Tales. After Portland homicide detective Nick Burkhardt discovers he''s descended from an elite line of criminal profilers known as "Grimms", he increasingly finds his responsibilities as a detective at odds with his new responsibilities as a Grimm.', 60, 'English', 'T18', 'http://www.nbc.com/grimm', 'https://static.tvmaze.com/uploads/images/medium_portrait/69/174906.jpg', '2011-10-28', '2012-04-28', 'INACTIVE');
